import { NextResponse } from "next/server";
import { Pool } from "pg";

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl:
    process.env.NODE_ENV === "production"
      ? { rejectUnauthorized: false }
      : undefined,
});

export async function POST(req: Request) {
  try {
    let token: string | null = null;

    // 1) Intentar leer token desde JSON
    try {
      const body = await req.json();
      if (body?.token != null) {
        token = String(body.token).trim();
      }
    } catch {
      // ignorar si no vino JSON válido
    }

    // 2) Si no vino en body, leerlo desde query ?token=
    if (!token) {
      const { searchParams } = new URL(req.url);
      const queryToken = searchParams.get("token");
      if (queryToken) {
        token = queryToken.trim();
      }
    }

    // 3) Validar token
    if (!token) {
      return NextResponse.json(
        { error: "Token requerido" },
        { status: 400 }
      );
    }

    // 4) Actualizar
    const result = await pool.query(
      `
      UPDATE plantillas_temporales
      SET pagado = 'si'
      WHERE token = $1
      `,
      [token]
    );

    // 5) Si no encontró filas
    if ((result.rowCount ?? 0) === 0) {
      return NextResponse.json(
        { error: "Token no encontrado" },
        { status: 404 }
      );
    }

    return NextResponse.json({
      ok: true,
      token,
      updated: result.rowCount,
    });
  } catch (error: any) {
    console.error("❌ Error actualizando pago:", error);
    return NextResponse.json(
      { error: error?.message || "Error actualizando pago" },
      { status: 500 }
    );
  }
}